target.echo:
$ErrorActionPreference = "Stop"
$distDir = Split-Path -Parent $MyInvocation.MyCommand.Path
$javaExe = Join-Path $distDir "runtime\bin\java.exe"

if (-not (Test-Path $javaExe)) {
    if ($env:JAVA_HOME -and (Test-Path (Join-Path $env:JAVA_HOME "bin\java.exe"))) {
        $javaExe = Join-Path $env:JAVA_HOME "bin\java.exe"
    } else {
        $javaExe = "java"
    }
}

Push-Location $distDir
try {
    if (Test-Path (Join-Path $distDir "bin\tools")) {
        $env:Path = (Join-Path $distDir "bin\tools") + ";" + $env:Path
    }
    & $javaExe "-Dsimplegenomehub.app.home=$distDir" -cp "app\SimpleGenomeHub.jar;lib/*;tbtools/lib/*" simplegenomehub.gui.SimpleGenomeHubMainPanel
    exit $LASTEXITCODE
}
finally {
    Pop-Location
}
